import os, re

# 1) All markdown routes from the filesystem
routes = {}
for root, _, files in os.walk("docs"):
    if "/.vitepress" in root or root.endswith("/.vitepress"):
        continue
    for fn in files:
        if not fn.endswith(".md"):
            continue
        rel = os.path.relpath(os.path.join(root, fn), "docs")
        route = "/" + rel[:-3]            # strip .md
        if route.endswith("/index"):
            route = route[:-5] or "/"     # index -> dir
        routes[route] = rel

# 2) All link values in config.ts (nav + sidebar)
cfg = open("docs/.vitepress/config.ts", encoding="utf-8").read()
links = set(m.group(1) for m in re.finditer(r"link:\s*'([^']+)'", cfg))
# normalise: strip trailing slash except root
def norm(l):
    return l[:-1] if (len(l) > 1 and l.endswith("/")) else l
links = {norm(l) for l in links}

linked = set()
orphans = []
for route, rel in sorted(routes.items()):
    if norm(route) in links:
        linked.add(route)
    else:
        orphans.append((route, rel))

print(f"TOTAL md files: {len(routes)}   linked: {len(linked)}   ORPHANS: {len(orphans)}\n")
print("=== ORPHANED DOCS (no sidebar/nav link) ===")
for route, rel in orphans:
    print(f"  {route:45s}  ({rel})")

# Also: links pointing to files that don't exist (dead sidebar entries)
print("\n=== sidebar/nav links with NO matching file ===")
route_set = {norm(r) for r in routes}
for l in sorted(links):
    base = l.split("#")[0]
    if base.startswith("/") and norm(base) not in route_set:
        print(f"  {l}")
