import os, re, glob

DOCS = "docs"
md_files = [f for f in glob.glob(f"{DOCS}/**/*.md", recursive=True)]
existing = set(os.path.normpath(f) for f in md_files)

def resolve(src, link):
    link = link.split("#")[0].strip()
    if not link: return None
    if re.match(r'^(https?:|mailto:|//)', link): return None
    # strip query
    link = link.split("?")[0]
    if link.startswith("/"):
        base = os.path.join(DOCS, link.lstrip("/"))
    else:
        base = os.path.join(os.path.dirname(src), link)
    base = os.path.normpath(base)
    # candidate files
    cands = []
    if base.endswith(".md"): cands.append(base)
    else:
        cands.append(base + ".md")
        cands.append(os.path.join(base, "index.md"))
        cands.append(base)  # maybe a non-md asset
    for c in cands:
        if os.path.normpath(c) in existing or os.path.exists(c):
            return None
    return base

link_re = re.compile(r'\[[^\]]*\]\(([^)]+)\)')
broken = {}
for f in md_files:
    txt = open(f, encoding="utf-8").read()
    for m in link_re.finditer(txt):
        tgt = m.group(1)
        miss = resolve(f, tgt)
        if miss is not None:
