    base=os.path.normpath(base)
    for c in ([base] if base.endswith(".md") else [base+".md",os.path.join(base,"index.md"),base]):
        if os.path.normpath(c) in existing or os.path.exists(c): return None
    return base
linkre=re.compile(r'\[[^\]]*\]\(([^)]+)\)')
broken={}
